#include <iostream>
#include <algorithm>
using namespace std;
bool check(int d,int e,int f)
{
    int num[9],count=0;
    if(e>999||f>999)
    {
       return false;
    }
    for(int i=1;i<=3;i++)
    {
        count++;
        num[count-1]=d%10;
        d/=10;
        count++;
        num[count-1]=e%10;
        e/=10;
        count++;
        num[count-1]=f%10;
        f/=10;
    }
    sort(num+0,num+9);
    if(num[0]==1&&num[1]==2&&num[2]==3&&num[3]==4&&num[4]==5&&num[5]==6&&num[6]==7&&num[7]==8&&num[8]==9)
    {
        return true;
    }
    else
    {
        return false;
    }
}
int main()
{
    int a=100,b=200,c=300;
    while(c<=999)
    {
        if(check(a,b,c))
        {
            cout<<a<<" "<<b<<" "<<c<<endl;
        }
        a++;
        b+=2;
        c+=3;
    }
    return 0;
}
